Patch:
// --------------------------------------------------------------------------
// 1. MEAL AND PROCESSED FOOD PATCH
// Injects Ingestion Contagion logic into Meals, Pemmican, and Kibble.
// --------------------------------------------------------------------------



        // Checks for ingestible items defined as Meals, inheriting from MealBase, or specific defNames.


            /Defs/ThingDef[ingestible/foodType="Meal" or @ParentName="MealBase" or defName="Pemmican" or defName="Kibble"]/comps

            // Case A: The item already has a  tag. Adds the component to the existing list.

                /Defs/ThingDef[ingestible/foodType="Meal" or @ParentName="MealBase" or defName="Pemmican" or defName="Kibble"]/comps



                        true
                        false




            // Case B: The item is missing the  tag. Creates the tag and adds the component.

                /Defs/ThingDef[ingestible/foodType="Meal" or @ParentName="MealBase" or defName="Pemmican" or defName="Kibble"]




                            true
                            false
